(()=>{
  const store=NexoraStore, UI=NexoraUI, A=NexoraAdmin;
  let competitions=[], groupConfigs=[], criteriaOrder=[];
  let wizard={step:0,draft:null,preview:null,running:false,progress:null,worker:null,requestId:'',previewStale:false};
  const DRAFT_KEY='new-generation-calendar-draft-v1';
  const steps=['Prerequisiti','Prima giornata','Vincoli obbligatori','Anteprima'];
  const isTouchDevice=()=>window.matchMedia&&window.matchMedia('(pointer: coarse)').matches;

  function selectedPlayingDays(){return UI.$$('#playingDaysBox input[name="playingDays"]:checked').map(x=>Number(x.value));}
  function setPlayingDays(days){const set=new Set((days&&days.length?days:[1,2,3,4,5,6,0]).map(Number));UI.$$('#playingDaysBox input[name="playingDays"]').forEach(x=>x.checked=set.has(Number(x.value)));}
  function compOptions(selected){return competitions.map(c=>`<option value="${c.id}" ${c.id===selected?'selected':''}>Vincente ${UI.esc(c.name)}</option>`).join('')||'<option value="">Nessuna competizione</option>';}
  function updateSuperCupVisibility(){const superBox=UI.$('#superCupBox');const superInput=UI.$('#superCupEnabled');const show=UI.$('#ruleFormat')?.value==='league_knockout'&&competitions.length>=2;if(superBox)superBox.style.display=show?'block':'none';if(superInput&&!show)superInput.checked=false;return show;}
  function criteriaMeta(id){return store.standingsCriterionMeta?store.standingsCriterionMeta(id):(store.STANDINGS_CRITERIA||[]).find(c=>c.id===id)||{id,label:id,short:id,direction:'desc'};}
  function normalizeCriteria(){criteriaOrder=store.normalizeStandingsCriteriaOrder?store.normalizeStandingsCriteriaOrder(criteriaOrder):criteriaOrder;}
  function moveCriterion(from,to){normalizeCriteria();if(from===to||from<0||to<0||from>=criteriaOrder.length||to>=criteriaOrder.length)return;const [item]=criteriaOrder.splice(from,1);criteriaOrder.splice(to,0,item);renderCriteriaEditor();toggle();render();}
  function renderCriteriaEditor(){
    normalizeCriteria();
    const box=UI.$('#standingsCriteriaEditor');if(!box)return;
    box.innerHTML=criteriaOrder.map((id,i)=>{const c=criteriaMeta(id);const dir=c.direction==='asc'?'minore e meglio':'maggiore e meglio';const touch=isTouchDevice();return `<div class="ranking-criterion-row ${touch?'touch-fallback':''}" data-criterion-index="${i}" data-criterion-id="${UI.esc(id)}" draggable="${touch?'false':'true'}"><span class="criterion-rank">${i+1}</span><button class="criterion-handle" type="button" data-pick-criterion="${i}" aria-label="Sposta criterio ${UI.esc(c.label)}">↕</button><div><strong>${UI.esc(c.label)}</strong><small>${UI.esc(dir)}</small></div><div class="criterion-actions"><button class="btn small" type="button" data-criterion-up="${i}" ${i===0?'disabled':''}>↑</button><button class="btn small" type="button" data-criterion-down="${i}" ${i===criteriaOrder.length-1?'disabled':''}>↓</button></div></div>`;}).join('');
    const summary=UI.$('#standingsCriteriaSummary');if(summary)summary.textContent='Ordine attivo: '+criteriaOrder.map((id,i)=>`${i+1}) ${criteriaMeta(id).label}`).join(' · ');
  }
  function ensureCriterionMoveModal(){let modal=UI.$('#criterionMoveModal');if(modal)return modal;modal=document.createElement('div');modal.className='modal group-move-modal criterion-move-modal';modal.id='criterionMoveModal';modal.setAttribute('role','dialog');modal.setAttribute('aria-modal','true');modal.innerHTML=`<div class="modal-content group-move-content"><div class="match-task-toolbar"><h2 id="criterionMoveTitle">Sposta criterio</h2><button class="btn danger" id="closeCriterionMoveModal" type="button">Chiudi</button></div><div id="criterionMoveBody" class="group-move-body"></div></div>`;document.body.appendChild(modal);return modal;}
  function openCriterionMoveModal(index){normalizeCriteria();const id=criteriaOrder[index];const c=criteriaMeta(id);if(!id)return;const modal=ensureCriterionMoveModal();UI.$('#criterionMoveTitle').textContent=`Sposta ${c.label}`;UI.$('#criterionMoveBody').innerHTML=`<div class="selected-team-summary"><span class="criterion-rank big">${index+1}</span><div><strong>${UI.esc(c.label)}</strong><small>Posizione attuale: ${index+1}</small></div></div><div class="group-move-actions">${criteriaOrder.map((targetId,i)=>`<button class="match-action-card compact ${i===index?'active':''}" type="button" data-mobile-criterion-from="${index}" data-mobile-criterion-to="${i}"><strong>Posizione ${i+1}</strong><small>${UI.esc(criteriaMeta(targetId).label)}</small></button>`).join('')}</div>`;modal.classList.add('open');}
  function closeCriterionMoveModal(){UI.$('#criterionMoveModal')?.classList.remove('open');}

  function renderCompetitionEditor(){const box=UI.$('#competitionsEditor');if(!box)return;competitions=competitions.length?competitions:[{id:'comp_oro',name:'Playoff Oro',startRank:1,teams:4}];box.innerHTML=competitions.map(c=>`<div class="competition-row" data-comp-id="${c.id}"><div><label>Nome</label><input data-comp-field="name" value="${UI.esc(c.name)}" placeholder="Playoff Oro"></div><div><label>Da posizione</label><input data-comp-field="startRank" type="number" min="1" value="${UI.esc(c.startRank)}"></div><div><label>N. squadre</label><input data-comp-field="teams" type="number" min="2" value="${UI.esc(c.teams)}"><p class="muted">2,4,8,16...</p></div>${competitions.length>1?`<button class="btn danger small" data-delete-competition="${c.id}" type="button">Elimina</button>`:'<span class="pill">Default</span>'}</div>`).join('');UI.$('#superCupHome').innerHTML=compOptions(UI.$('#superCupHome').value||competitions[0]?.id||'');UI.$('#superCupAway').innerHTML=compOptions(UI.$('#superCupAway').value||competitions[1]?.id||'');updateSuperCupVisibility();}
  function renderGroupsEditor(){const box=UI.$('#groupsEditor');if(!box)return;groupConfigs=groupConfigs.length?groupConfigs:[{name:'Girone A',size:4,qualifiers:2},{name:'Girone B',size:4,qualifiers:2}];box.innerHTML=groupConfigs.map((g,i)=>`<div class="competition-row" data-group-index="${i}"><div><label>Nome girone</label><input data-group-field="name" value="${UI.esc(g.name)}"></div><div><label>Squadre nel girone</label><input data-group-field="size" type="number" min="2" value="${UI.esc(g.size)}"></div><div><label>Squadre qualificate</label><input data-group-field="qualifiers" type="number" min="1" value="${UI.esc(g.qualifiers)}"><p class="muted">Almeno 1 per girone. Totale valido: almeno 2 qualificate complessive.</p></div>${groupConfigs.length>2?`<button class="btn danger small" data-delete-group="${i}" type="button">Elimina</button>`:'<span class="pill">Girone</span>'}</div>`).join('');}
  function readGroupsFromDom(){const rows=UI.$$('#groupsEditor [data-group-index]');groupConfigs=rows.map((row,i)=>({name:row.querySelector('[data-group-field="name"]').value.trim()||`Girone ${String.fromCharCode(65+i)}`,size:Number(row.querySelector('[data-group-field="size"]').value)||2,qualifiers:Number(row.querySelector('[data-group-field="qualifiers"]').value)||0}));}
  function readCompetitionsFromDom(){const rows=UI.$$('#competitionsEditor [data-comp-id]');competitions=rows.map(row=>({id:row.dataset.compId,name:row.querySelector('[data-comp-field="name"]').value.trim()||'Playoff',startRank:Number(row.querySelector('[data-comp-field="startRank"]').value)||1,teams:Number(row.querySelector('[data-comp-field="teams"]').value)||4}));}

  function fill(){const s=A.state(),r=s.rules;competitions=(r.eliminationCompetitions||[]).map(c=>({...c}));groupConfigs=(r.groupConfigs||store.defaultGroupConfigs()).map(g=>({...g}));criteriaOrder=store.normalizeStandingsCriteriaOrder?store.normalizeStandingsCriteriaOrder(r.standingsCriteriaOrder):[...(r.standingsCriteriaOrder||[])];UI.$('#ruleName').value=r.name;UI.$('#ruleFormat').value=r.format;UI.$('#isKingsLeague').checked=!!r.isKingsLeague;UI.$('#fieldCount').value=r.fieldCount;UI.$('#groupFieldPolicy').value=r.groupFieldPolicy||'auto';UI.$('#oneDay').checked=!!r.oneDay;UI.$('#startDate').value=r.startDate;UI.$('#endDate').value=r.endDate;UI.$('#startTime').value=r.startTime;UI.$('#matchDuration').value=r.matchDuration;UI.$('#breakMinutes').value=r.breakMinutes;UI.$('#oneDayPauseEnabled').checked=!!r.oneDayPauseEnabled;UI.$('#oneDayPauseStart').value=r.oneDayPauseStart||'13:00';UI.$('#oneDayPauseDuration').value=r.oneDayPauseDuration||60;setPlayingDays(r.playingDays);UI.$('#superCupEnabled').checked=!!r.superCup?.enabled;renderGroupsEditor();renderCompetitionEditor();renderCriteriaEditor();UI.$('#superCupHome').value=r.superCup?.homeCompetitionId||competitions[0]?.id||'';UI.$('#superCupAway').value=r.superCup?.awayCompetitionId||competitions[1]?.id||'';toggle();}
  function readInto(s){readCompetitionsFromDom();readGroupsFromDom();normalizeCriteria();const fd=new FormData(UI.$('#rulesForm'));const format=fd.get('format');const totalQ=groupConfigs.reduce((sum,g)=>sum+(Number(g.qualifiers)||0),0);s.rules={...s.rules,name:fd.get('name')?.trim()||'New Generation',format,isKingsLeague:Boolean(fd.get('isKingsLeague')),groupCount:format==='groups_knockout'?groupConfigs.length:2,groupConfigs:format==='groups_knockout'?groupConfigs:s.rules.groupConfigs,playoffTeams:format==='groups_knockout'?totalQ:(Number(s.rules.playoffTeams)||4),eliminationCompetitions:format==='league_knockout'?competitions:competitions,superCup:{enabled:format==='league_knockout'&&competitions.length>=2?Boolean(fd.get('superCupEnabled')):false,homeCompetitionId:fd.get('superCupHome')||competitions[0]?.id||'',awayCompetitionId:fd.get('superCupAway')||competitions[1]?.id||''},fieldCount:Number(fd.get('fieldCount'))||1,groupFieldPolicy:format==='groups_knockout'?(fd.get('groupFieldPolicy')||'auto'):'auto',oneDay:Boolean(fd.get('oneDay')),startDate:fd.get('startDate')||'',endDate:fd.get('endDate')||'',startTime:fd.get('startTime')||'09:00',endTime:'',matchDuration:Number(fd.get('matchDuration'))||40,breakMinutes:Number(fd.get('breakMinutes'))||0,oneDayPauseEnabled:Boolean(fd.get('oneDayPauseEnabled')),oneDayPauseStart:fd.get('oneDayPauseStart')||'13:00',oneDayPauseDuration:Number(fd.get('oneDayPauseDuration'))||0,playingDays:selectedPlayingDays(),standingsCriteriaOrder:[...criteriaOrder],calendarCustomization:store.normalizeCalendarCustomization(s.rules.calendarCustomization)};}
  function currentDraftState(){const draft=JSON.parse(JSON.stringify(A.state()));readInto(draft);return store.normalizeState(draft);}
  function loadCalendarDraft(){try{const raw=localStorage.getItem(DRAFT_KEY);if(!raw)return null;const saved=JSON.parse(raw);return saved&&saved.calendarCustomization?saved:null;}catch(_){return null;}}
  function clearCalendarDraft({silent=false}={}){try{localStorage.removeItem(DRAFT_KEY);}catch(_){}if(wizard)wizard.draftCleared=true;if(!silent)A.flash('#rulesMessage','Bozza calendario eliminata.','ok');}
  function saveCalendarDraft({silent=false}={}){if(!wizard.draft)return false;syncWizardFromDom();const payload={version:3,savedAt:new Date().toISOString(),step:wizard.step,format:wizard.draft.rules.format,calendarCustomization:wizard.draft.rules.calendarCustomization};try{localStorage.setItem(DRAFT_KEY,JSON.stringify(payload));wizard.draftCleared=false;if(!silent)A.flash('#rulesMessage','Bozza calendario salvata. Potrai riaprirla dal wizard senza creare partite.','ok');return true;}catch(_){if(!silent)A.flash('#rulesMessage','Impossibile salvare la bozza nel browser.','error');return false;}}
  function applyCalendarDraft(draft,saved){if(!saved)return {loaded:false,step:0};draft.rules.calendarCustomization=store.normalizeCalendarCustomization(saved.calendarCustomization);return {loaded:true,step:Math.max(0,Math.min(3,Number(saved.step)||0)),savedAt:saved.savedAt||''};}
  function toggle(){const one=UI.$('#oneDay').checked,format=UI.$('#ruleFormat').value;UI.$$('.one-day-field').forEach(x=>x.style.display=one?'block':'none');const pauseControls=UI.$('#oneDayPauseControls');if(pauseControls)pauseControls.style.display=(one&&UI.$('#oneDayPauseEnabled')?.checked)?'grid':'none';UI.$$('.multi-day-field').forEach(x=>x.style.display=one?'none':'block');UI.$$('.groups-only').forEach(x=>x.style.display=format==='groups_knockout'?'block':'none');UI.$$('.league-ko-only').forEach(x=>x.style.display=format==='league_knockout'?'block':'none');updateSuperCupVisibility();const draft=currentDraftState();const min=store.minimumTeams(draft.rules),hint=store.FORMAT_HELP[format]||'';const groupHint=format==='groups_knockout'?`<br><span class="muted">Gironi configurati: ${draft.rules.groupConfigs.map(g=>`${UI.esc(g.name)} ${g.size} squadre / ${g.qualifiers} qualificate`).join(' · ')}</span>`:'';const policyHint=UI.$('#groupFieldPolicyHint');if(policyHint){const groups=draft.rules.groupConfigs.length,fields=Number(draft.rules.fieldCount)||1,active=draft.rules.groupFieldPolicy==='fixed_by_group';policyHint.textContent=active?(groups===fields?`Attivo: ogni girone usa prioritariamente il proprio campo (${draft.rules.groupConfigs.map((g,i)=>`${g.name} -> Campo ${i+1}`).join(' · ')}); un campo libero può ospitare temporaneamente l’altro girone.`:`Per attivarla servono stesso numero di gironi e campi. Ora: ${groups} gironi e ${fields} campi.`):'Automatica: il calendario sceglie il primo campo libero rispettando sovrapposizioni e riposi.';}UI.$('#formatHint').innerHTML=`<div class="help-box"><strong>${UI.esc(store.FORMAT_LABELS[format]||format)}</strong><br>${UI.esc(hint)}<br><span class="muted">Minimo squadre richieste: ${min}</span>${groupHint}</div>`;}
  function calendarStatusMarkup(s){
    if(!(s.matches||[]).length)return '<div class="calendar-status-card"><strong>Calendario non ancora generato</strong><span>Salva regole, squadre e gironi; poi usa "Genera calendario ottimale". Nessuna partita viene creata automaticamente.</span></div>';
    const fresh=store.isCalendarFresh(s),stats=store.calendarConsecutiveStats(s.matches,s.rules,s);
    const metric=stats.uniqueTeams===0?'Nessuna squadra gioca due partite consecutive.':`Squadre consecutive: ${stats.uniqueTeams} · Occorrenze: ${stats.totalOccurrences}${stats.teamNames.length?' · '+UI.esc(stats.teamNames.join(', ')):''}`;
    return `<div class="calendar-status-card"><strong>${fresh?'Calendario ottimale generato':'Calendario da rivedere'}</strong><span>${fresh?'Le partite sono allineate alla configurazione corrente.':'Regole, squadre o gironi sono cambiati: genera una nuova anteprima e confermala per sostituire il calendario.'}</span><span>${metric}</span></div>`;
  }
  function render(){const s=A.state();UI.$('#tournamentSummary').innerHTML=UI.rulesSummary(s);UI.$('#generatedCalendar').innerHTML=calendarStatusMarkup(s)+UI.matchList(s);const draft=currentDraftState();const plan=store.generationPlan(draft);UI.$('#generationPreview').innerHTML=`<div class="message ${plan.ok?'ok':'error'}">${UI.esc(plan.message)}</div>`;const est=plan.estimate;UI.$('#suggestedEndHint').textContent=(!draft.rules.oneDay&&est?.ok)?`Fine consigliata: ${est.suggestedEndDate}`:'';UI.$('#calendarAdvisor').innerHTML=est?`<div class="advisor-card"><strong>Consiglio calendario</strong><span>${UI.esc(est.message)}</span><span class="muted">Il calcolo considera formato, gironi, qualificate, campi disponibili, giorni di gioco e vincoli anti-sovrapposizione.</span></div>`:'';}

  function ensureWizard(){let modal=UI.$('#calendarWizardModal');if(modal)return modal;modal=document.createElement('div');modal.id='calendarWizardModal';modal.className='calendar-wizard-modal';modal.setAttribute('role','dialog');modal.setAttribute('aria-modal','true');modal.innerHTML=`<div class="calendar-wizard-panel"><div class="calendar-wizard-head"><div><span class="article-kicker">Ottimizzazione globale</span><h2>Genera calendario ottimale</h2><p class="muted">La ricerca esamina tutte le configurazioni rilevanti con pruning sicuro. Le partite vengono salvate solo dopo conferma finale.</p></div><button class="btn danger" type="button" data-calendar-wizard-close>Chiudi</button></div><div id="calendarWizardContent"></div></div>`;document.body.appendChild(modal);return modal;}
  function setGenerationBusy(busy){const button=UI.$('#generateCalendarBtn');if(button)button.disabled=Boolean(busy);}
  function stopCalendarWorker(){if(wizard.worker){wizard.worker.terminate();wizard.worker=null;}wizard.requestId='';}
  function openWizard(){const draft=currentDraftState();draft.rules.calendarCustomization=store.normalizeCalendarCustomization(draft.rules.calendarCustomization);const stored=loadCalendarDraft();const saved=applyCalendarDraft(draft,stored);wizard={step:saved.loaded?saved.step:0,draft,preview:null,running:false,progress:null,worker:null,requestId:'',loadedDraft:saved.loaded,savedAt:saved.savedAt||'',draftCleared:false,previewStale:false};ensureWizard().classList.add('open');document.body.classList.add('ng-overlay-open');renderWizard();}
  function closeWizard({saveDraft=true}={}){stopCalendarWorker();setGenerationBusy(false);if(saveDraft&&wizard.draft&&!wizard.draftCleared)saveCalendarDraft({silent:true});UI.$('#calendarWizardModal')?.classList.remove('open');document.body.classList.remove('ng-overlay-open');wizard={step:0,draft:null,preview:null,running:false,progress:null,worker:null,requestId:'',previewStale:false};}
  function fieldsOptions(selected=''){const count=Number(wizard.draft?.rules?.fieldCount)||1;return '<option value="">Automatico</option>'+Array.from({length:count},(_,i)=>`<option value="Campo ${i+1}" ${selected===`Campo ${i+1}`?'selected':''}>Campo ${i+1}</option>`).join('');}
  function groupsOptions(selected=''){const groups=(wizard.draft?.rules?.groupConfigs||[]).map(g=>g.name);return '<option value="">Classifica unica</option>'+groups.map(g=>`<option value="${UI.esc(g)}" ${g===selected?'selected':''}>${UI.esc(g)}</option>`).join('');}
  function teamsForGroup(groupName=''){if(!wizard.draft)return[];if(wizard.draft.rules.format!=='groups_knockout'||!groupName)return wizard.draft.teams||[];const g=store.plannedGroups(wizard.draft).find(x=>x.name===groupName);return g?g.teams:[];}
  function teamOptions(selected='',groupName=''){return '<option value="">Seleziona</option>'+teamsForGroup(groupName).map(t=>`<option value="${t.id}" ${t.id===selected?'selected':''}>${UI.esc(t.name)}</option>`).join('');}
  function allTeamOptions(selected=''){return '<option value="">Seleziona</option>'+(wizard.draft?.teams||[]).map(t=>`<option value="${t.id}" ${t.id===selected?'selected':''}>${UI.esc(t.name)}</option>`).join('');}
  function prereqStep(){const pre=store.calendarPrerequisites(wizard.draft);return `<div class="calendar-check-list">${pre.items.map(i=>`<div class="calendar-check ${i.ok?'ok':'warn'}"><strong>${UI.esc(i.label)}</strong><span>${i.ok?'OK':UI.esc(i.message)}</span></div>`).join('')}</div>`;}
  function firstRoundStep(){const locks=wizard.draft.rules.calendarCustomization.firstRoundLocks;return `<div class="calendar-rule-list">${locks.map((l,i)=>`<div class="calendar-editor-row" data-lock-index="${i}"><div><label>Girone/fase</label><select data-lock-field="groupName">${groupsOptions(l.groupName)}</select></div><div><label>Squadra casa</label><select data-lock-field="homeTeamId">${teamOptions(l.homeTeamId,l.groupName)}</select></div><div><label>Squadra ospite</label><select data-lock-field="awayTeamId">${teamOptions(l.awayTeamId,l.groupName)}</select></div><div><label>Orario</label><input data-lock-field="requiredTime" type="time" value="${UI.esc(l.requiredTime)}"></div><div><label>Campo</label><select data-lock-field="requiredField">${fieldsOptions(l.requiredField)}</select></div><button class="btn danger small" type="button" data-remove-lock="${i}">Elimina</button></div>`).join('')||'<div class="empty">Nessun accoppiamento fissato. L algoritmo completera la prima giornata.</div>'}</div><button class="btn primary margin-top" type="button" data-add-lock>Aggiungi partita prima giornata</button>`;}
  function constraintValidation(){return wizard.draft?store.validateCalendarConstraintDefinitions(wizard.draft):{ok:true,issues:[]};}
  function issueMapBySource(validation){const map=new Map();(validation?.issues||[]).forEach(issue=>{if(issue.sourceId&&!map.has(issue.sourceId))map.set(issue.sourceId,issue);});return map;}
  function constraintsStep(){
    const custom=wizard.draft.rules.calendarCustomization;
    const validation=constraintValidation();
    const issueMap=issueMapBySource(validation);
    const times=store.calendarAvailableTimes(wizard.draft);
    const timeRules=custom.teamDebuts.map((rule,index)=>({rule,index}));
    const rowError=rule=>{const issue=issueMap.get(rule.id);return issue?`<small class="calendar-field-error" role="alert">${UI.esc(issue.message)}</small>`:'';};
    const timeOptions=selected=>times.length?times.map(time=>`<option value="${time}" ${time===selected?'selected':''}>${time}</option>`).join(''):'<option value="">Nessun orario disponibile</option>';
    const timeRows=timeRules.map(({rule,index})=>{const invalid=issueMap.has(rule.id);return `<div class="calendar-editor-row debut constraint-row" data-debut-index="${index}"><div><label>Squadra</label><select data-debut-field="teamId" aria-invalid="${invalid?'true':'false'}">${allTeamOptions(rule.teamId)}</select></div><div><label>Orario della prima partita</label><select data-debut-field="value" ${times.length?'':'disabled'} aria-invalid="${invalid?'true':'false'}">${timeOptions(rule.value)}</select>${rowError(rule)}</div><div class="constraint-row-actions"><button class="btn danger small" type="button" data-remove-debut="${index}">Elimina</button></div></div>`;}).join('')||'<div class="empty">Nessun vincolo sull’orario d’esordio.</div>';
    const generalErrors=(validation.issues||[]).filter(issue=>!issue.sourceId).map(issue=>`<div class="message error">${UI.esc(issue.message)}</div>`).join('');
    return `${generalErrors}<section class="calendar-constraint-block"><h3>Riposo minimo obbligatorio</h3><p class="muted">Questo valore è un vincolo rigido, non una preferenza. Se è maggiore della pausa tra gli slot, lo scheduler inserisce il numero minimo di turni di riposo necessario.</p><div class="form-grid"><div><label>Minuti di riposo tra due partite</label><input data-cal-field="minRestMinutes" type="number" min="0" max="240" value="${UI.esc(custom.minRestMinutes)}"></div></div></section><section class="calendar-constraint-block"><h3>Orario d’esordio della squadra</h3><p class="muted">Seleziona l’orario esatto della prima partita cronologica della squadra. Sono proposti solo gli slot compatibili con data, durata, pausa e campi configurati.</p><div class="calendar-rule-list">${timeRows}</div><button class="btn small primary margin-top" type="button" data-add-debut-time ${times.length?'':'disabled'}>Aggiungi vincolo orario</button>${!wizard.draft.rules.oneDay?'<div class="message error margin-top">Il vincolo di orario è disponibile solo per un torneo in un giorno.</div>':''}</section>`;
  }

  function problemStep(result){const conflicts=result?.conflicts||result?.issues||[];return conflicts.length?Math.max(0,Math.min(3,Number(conflicts[0].step)||2)):2;}
  function markPreviewStale(){if(wizard.preview)wizard.previewStale=true;}
  function runPreview(){
    if(wizard.running)return;
    syncWizardFromDom();
    const validation=constraintValidation();
    if(!validation.ok){wizard.preview=null;wizard.previewStale=true;wizard.step=2;renderWizard();return validation;}
    wizard.preview=null;wizard.previewStale=false;wizard.step=3;wizard.progress={phase:'starting',nodes:0,pruned:0};wizard.running=true;setGenerationBusy(true);renderWizard();
    if(typeof Worker==='undefined'){
      wizard.running=false;setGenerationBusy(false);wizard.preview={ok:false,message:'Il browser non supporta il calcolo in background richiesto per la ricerca ottimale.',conflicts:[],issues:[]};renderWizard();return wizard.preview;
    }
    stopCalendarWorker();
    const requestId=`calendar_${Date.now()}_${Math.random().toString(36).slice(2,8)}`;
    const worker=new Worker('assets/js/calendar-worker.js');
    wizard.worker=worker;wizard.requestId=requestId;
    worker.onmessage=event=>{
      const data=event.data||{};if(data.requestId!==wizard.requestId)return;
      if(data.type==='progress'){
        wizard.progress=data.progress||{};
        const now=Date.now();if(now-(wizard.progressRenderedAt||0)>250){wizard.progressRenderedAt=now;renderWizard();}
        return;
      }
      if(data.type==='result'){
        worker.terminate();wizard.worker=null;wizard.requestId='';wizard.running=false;setGenerationBusy(false);wizard.preview=data.result;wizard.previewStale=false;renderWizard();return;
      }
      if(data.type==='error'){
        worker.terminate();wizard.worker=null;wizard.requestId='';wizard.running=false;setGenerationBusy(false);wizard.preview={ok:false,message:`Errore tecnico durante la ricerca ottimale: ${data.message||'errore sconosciuto'}`,conflicts:[],issues:[]};renderWizard();
      }
    };
    worker.onerror=event=>{if(worker!==wizard.worker)return;worker.terminate();wizard.worker=null;wizard.requestId='';wizard.running=false;setGenerationBusy(false);wizard.preview={ok:false,message:`Errore tecnico durante la ricerca ottimale: ${event.message||'worker non disponibile'}`,conflicts:[],issues:[]};renderWizard();};
    worker.postMessage({requestId,state:wizard.draft});
  }
  function optimalSearchMarkup(){
    const progress=wizard.progress||{};
    const best=progress.best;
    const bestText=best?`Migliore soluzione completa trovata finora: ${best.uniqueConsecutiveTeams} squadre consecutive, ${best.consecutiveOccurrences} occorrenze.`:'Nessuna soluzione completa trovata finora.';
    return `<div class="calendar-search-status" role="status" aria-live="polite"><span class="calendar-search-spinner" aria-hidden="true"></span><div><h3>Ricerca del calendario ottimale in corso…</h3><p>L’interfaccia resta utilizzabile mentre il calcolo viene eseguito fuori dal thread principale.</p><p class="muted">Orizzonte analizzato: ${UI.esc(progress.horizon||'-')} slot · Nodi esaminati: ${UI.esc(progress.nodes||0)} · Rami potati in modo sicuro: ${UI.esc(progress.pruned||0)}</p><p>${UI.esc(bestText)}</p></div></div>`;
  }
  function metricsMarkup(result){
    const stats=result?.consecutiveStats;if(!stats)return'';
    const names=stats.teamNames?.length?`<span><strong>Squadre coinvolte:</strong> ${UI.esc(stats.teamNames.join(', '))}</span>`:'<span class="calendar-zero-result">Nessuna squadra giocherà due partite consecutive.</span>';
    const proof=result.optimality?.provenOptimal?`<span><strong>Ottimo globale dimostrato:</strong> sì · ${UI.esc(result.optimality.nodes||0)} nodi · ${UI.esc(result.optimality.pruned||0)} pruning sicuri.</span>`:'';
    return `<section class="calendar-optimal-metrics"><h3>Risultato dell’ottimizzazione</h3><span><strong>Squadre con almeno due partite consecutive:</strong> ${stats.uniqueTeams}</span><span><strong>Occorrenze consecutive complessive:</strong> ${stats.totalOccurrences}</span>${names}${stats.threePlusTeamNames?.length?`<span><strong>Serie di almeno tre:</strong> ${UI.esc(stats.threePlusTeamNames.join(', '))}</span>`:''}${proof}</section>`;
  }
  function ruleReportMarkup(report){
    if(!report)return'';const warnings=report.warnings||[],checks=report.debutChecks||[];
    const checkHtml=checks.length?`<div class="calendar-debut-checks"><h4>Controllo vincoli di esordio</h4><table><thead><tr><th>Squadra</th><th>Vincolo</th><th>Richiesto</th><th>Ottenuto</th><th>Esito</th></tr></thead><tbody>${checks.map(c=>`<tr><td>${UI.esc(c.team)}</td><td>${UI.esc(c.rule)}</td><td>${UI.esc(c.requested)}</td><td>${UI.esc(c.obtained)}</td><td><span class="calendar-report-row ${c.ok?'ok':'warn'}">${UI.esc(c.status)}</span></td></tr>`).join('')}</tbody></table></div>`:'';
    return `<section class="calendar-rule-report"><h3>Vincoli obbligatori verificati</h3><div class="calendar-report-grid"><div>${(report.respectedHardConstraints||[]).map(x=>`<span class="calendar-report-row ok">${UI.esc(x)}</span>`).join('')}</div></div>${checkHtml}${warnings.length?`<div class="calendar-conflict-list">${warnings.map(w=>`<div class="calendar-conflict warn"><strong>${UI.esc(w.rule)}</strong><span>${UI.esc(w.message)}</span></div>`).join('')}</div>`:''}</section>`;
  }
  function conflictActions(c){if(!c.actions?.includes('remove'))return'';const key=`${UI.esc(c.sourceType)}:${UI.esc(c.sourceId)}`;return `<div class="calendar-conflict-actions"><button class="btn danger small" type="button" data-conflict-remove="${key}">Rimuovi regola</button></div>`;}
  function infeasibleMarkup(p){const conflicts=p.conflicts||p.issues||[];const conflictHtml=conflicts.length?conflicts.map(c=>`<div class="calendar-conflict ${c.nonRelaxable?'hard':''}"><strong>${UI.esc(c.rule||'Vincolo')}</strong><span>${UI.esc(c.message||'Vincolo non rispettato.')}</span><small>Suggerimento: ${UI.esc(c.suggestion||'Modifica la regola e riesegui la validazione.')}</small>${conflictActions(c)}</div>`).join(''):`<div class="calendar-conflict hard"><strong>Pianificazione</strong><span>${UI.esc(p.message||'Nessuna soluzione valida trovata.')}</span></div>`;return `<div class="calendar-infeasible-panel"><h3>Impossibile generare un calendario valido</h3><p>Tutti i vincoli sono obbligatori: nessuna preferenza viene rilassata. Il calendario precedente non è stato modificato.</p><div class="calendar-conflict-list">${conflictHtml}</div><div class="calendar-wizard-actions inline"><button class="btn primary" type="button" data-calendar-edit-rules>Modifica i vincoli</button><button class="btn danger" type="button" data-calendar-cancel>Annulla</button></div></div>`;}
  function previewStep(){
    if(wizard.running)return optimalSearchMarkup();
    if(wizard.previewStale)return `<div class="calendar-infeasible-panel"><h3>Anteprima obsoleta</h3><p>I vincoli sono stati modificati. Il calendario deve essere ricalcolato completamente.</p><div class="calendar-wizard-actions inline"><button class="btn primary" type="button" data-calendar-preview>Ricalcola il calendario ottimale</button><button class="btn" type="button" data-calendar-edit-rules>Modifica i vincoli</button></div></div>`;
    if(!wizard.preview)return `<div class="calendar-search-ready"><h3>Ricerca esatta pronta</h3><p>Avvia l’analisi completa per trovare il minimo globale di squadre con partite consecutive.</p><button class="btn primary" type="button" data-calendar-preview>Genera calendario ottimale</button></div>`;
    const p=wizard.preview,draft=p.draft||wizard.draft;if(!p.ok)return infeasibleMarkup(p);
    const issues=p.validation?.issues||p.issues||[];const issueHtml=issues.length?issues.map(i=>`<div class="calendar-conflict ${i.severity==='error'?'':'warn'}"><strong>${UI.esc(i.rule||'Vincolo')}</strong><span>${UI.esc(i.message)}</span></div>`).join(''):'<div class="calendar-check ok"><strong>Fattibile</strong><span>Tutti i vincoli obbligatori risultano rispettati.</span></div>';
    return `<div class="calendar-preview-grid"><div><div class="message ok"><strong>Calendario ottimale generato</strong><br>${UI.esc(p.message)}</div>${metricsMarkup(p)}<div class="calendar-preview-list stack margin-top">${UI.matchList(draft,p.previewMatches,false)}</div>${ruleReportMarkup(p.ruleReport)}</div><aside><h3>Report di correttezza</h3>${issueHtml}</aside></div>`;
  }
  function renderWizard(){
    const modal=ensureWizard(),box=UI.$('#calendarWizardContent');
    const validation=wizard.step===2?constraintValidation():{ok:true,issues:[]};
    const body=[prereqStep,firstRoundStep,constraintsStep,previewStep][wizard.step]();
    const draftNote=wizard.loadedDraft?`<div class="message ok">Bozza calendario recuperata${wizard.savedAt?' · '+UI.esc(new Date(wizard.savedAt).toLocaleString('it-IT')):''}.</div>`:'';
    const nextDisabled=wizard.step===2&&!validation.ok;
    box.innerHTML=`${draftNote}<div class="calendar-wizard-steps">${steps.map((stepLabel,i)=>`<button class="calendar-wizard-step ${i===wizard.step?'active':''}" type="button" data-calendar-step="${i}" ${wizard.running?'disabled':''}>${i+1}. ${UI.esc(stepLabel)}</button>`).join('')}</div><div class="calendar-wizard-body">${body}</div><div class="calendar-wizard-actions"><button class="btn" type="button" data-calendar-prev ${wizard.step===0||wizard.running?'disabled':''}>Indietro</button><div class="row-actions"><button class="btn" type="button" data-calendar-save-draft ${wizard.running?'disabled':''}>Salva bozza</button><button class="btn danger" type="button" data-calendar-clear-draft ${wizard.running?'disabled':''}>Nuova configurazione</button>${wizard.step<3?`<button class="btn primary" type="button" data-calendar-next ${nextDisabled||wizard.running?'disabled':''}>Avanti</button>`:`${!wizard.running?'<button class="btn" type="button" data-calendar-preview>Ricalcola ottimo globale</button>':''}<button class="btn primary" type="button" data-calendar-confirm ${!(wizard.preview&&wizard.preview.ok)||wizard.previewStale||wizard.running?'disabled':''}>Conferma e crea calendario</button>`}</div></div>`;
  }
  function syncWizardFromDom(){
    if(!wizard.draft)return;
    const custom=store.normalizeCalendarCustomization(wizard.draft.rules.calendarCustomization);
    const rest=UI.$('[data-cal-field="minRestMinutes"]');if(rest)custom.minRestMinutes=Number(rest.value)||0;
    UI.$$('#calendarWizardModal [data-lock-index]').forEach(row=>{const index=Number(row.dataset.lockIndex),lock=custom.firstRoundLocks[index];if(!lock)return;row.querySelectorAll('[data-lock-field]').forEach(input=>lock[input.dataset.lockField]=input.value);});
    UI.$$('#calendarWizardModal [data-debut-index]').forEach(row=>{const index=Number(row.dataset.debutIndex),rule=custom.teamDebuts[index];if(!rule)return;row.querySelectorAll('[data-debut-field]').forEach(input=>rule[input.dataset.debutField]=input.value);});
    wizard.draft.rules.calendarCustomization=store.normalizeCalendarCustomization(custom);
  }
  function applyConflictAction(raw,action){if(!raw||!wizard.draft||action!=='remove')return;syncWizardFromDom();const [type,id]=String(raw).split(':');const c=wizard.draft.rules.calendarCustomization;if(type==='firstRoundLock'){const i=c.firstRoundLocks.findIndex(x=>x.id===id);if(i>=0)c.firstRoundLocks.splice(i,1);wizard.step=1;}if(type==='teamDebut'){const i=c.teamDebuts.findIndex(x=>x.id===id);if(i>=0)c.teamDebuts.splice(i,1);wizard.step=2;}wizard.preview=null;wizard.previewStale=false;wizard.draft.rules.calendarCustomization=store.normalizeCalendarCustomization(c);saveCalendarDraft({silent:true});renderWizard();}
  function confirmCalendar(){
    if(wizard.running)return;syncWizardFromDom();
    const preview=wizard.preview;if(!preview?.ok||wizard.previewStale){wizard.step=3;renderWizard();return;}
    const state=A.state();
    if(state.matches.length){const hasReports=state.matches.some(match=>(match.goals&&match.goals.length)||(match.cards&&match.cards.length)||match.status==='played'||match.status==='live');const warning=hasReports?'Esiste già un calendario con risultati o referti. Confermando verrà sostituito integralmente e i dati precedenti non saranno preservati. Continuare?':'Esiste già un calendario. Confermando verrà sostituito integralmente con la soluzione ottimale mostrata. Continuare?';if(!confirm(warning))return;}
    readInto(state);state.rules.calendarCustomization=store.normalizeCalendarCustomization(wizard.draft.rules.calendarCustomization);state.matches=structuredClone(preview.previewMatches||preview.draft?.matches||[]);store.autoResolveKnockout(state);state.calendarSignature=store.scheduleSignature(state);store.alignState(state);A.save(state);clearCalendarDraft({silent:true});A.flash('#rulesMessage',preview.message,'ok');closeWizard({saveDraft:false});fill();render();
  }

  document.addEventListener('DOMContentLoaded',()=>{fill();render();const gen=UI.$('#generateCalendarBtn');if(gen)gen.textContent='Genera calendario ottimale';});
  ['#oneDay','#ruleFormat','#isKingsLeague','#superCupEnabled','#superCupHome','#superCupAway','#fieldCount','#groupFieldPolicy','#startDate','#endDate','#startTime','#matchDuration','#breakMinutes','#oneDayPauseEnabled','#oneDayPauseStart','#oneDayPauseDuration'].forEach(sel=>UI.$(sel)?.addEventListener('change',()=>{toggle();render();}));
  UI.$$('#playingDaysBox input[name="playingDays"]').forEach(x=>x.addEventListener('change',()=>{toggle();render();}));
  UI.$('#groupsEditor')?.addEventListener('input',()=>{readGroupsFromDom();toggle();render();});
  UI.$('#competitionsEditor')?.addEventListener('input',()=>{readCompetitionsFromDom();toggle();render();});
  UI.$('#addGroupBtn')?.addEventListener('click',()=>{readGroupsFromDom();groupConfigs.push({name:`Girone ${String.fromCharCode(65+groupConfigs.length)}`,size:4,qualifiers:1});renderGroupsEditor();toggle();render();});
  UI.$('#addCompetitionBtn')?.addEventListener('click',()=>{readCompetitionsFromDom();const start=competitions.length?Math.max(...competitions.map(c=>c.startRank+c.teams)):1;const names=['Playoff Argento','Playoff Bronzo','Playoff Platino'];competitions.push({id:store.uid('comp'),name:names[competitions.length-1]||`Playoff ${competitions.length+1}`,startRank:start,teams:4});renderCompetitionEditor();toggle();render();});

  document.addEventListener('click',e=>{
    const gc=e.target.closest('[data-delete-group]');if(gc){readGroupsFromDom();groupConfigs.splice(Number(gc.dataset.deleteGroup),1);renderGroupsEditor();toggle();render();return;}
    const delComp=e.target.closest('[data-delete-competition]');if(delComp){competitions=competitions.filter(c=>c.id!==delComp.dataset.deleteCompetition);renderCompetitionEditor();toggle();render();return;}
    const up=e.target.closest('[data-criterion-up]');if(up){moveCriterion(Number(up.dataset.criterionUp),Number(up.dataset.criterionUp)-1);return;}
    const down=e.target.closest('[data-criterion-down]');if(down){moveCriterion(Number(down.dataset.criterionDown),Number(down.dataset.criterionDown)+1);return;}
    const pick=e.target.closest('[data-pick-criterion]');if(pick){if(isTouchDevice())openCriterionMoveModal(Number(pick.dataset.pickCriterion));return;}
    const mobile=e.target.closest('[data-mobile-criterion-from]');if(mobile){moveCriterion(Number(mobile.dataset.mobileCriterionFrom),Number(mobile.dataset.mobileCriterionTo));closeCriterionMoveModal();return;}
    if(e.target.id==='closeCriterionMoveModal')closeCriterionMoveModal();
    if(e.target.id==='criterionMoveModal'){e.preventDefault();e.stopPropagation();closeCriterionMoveModal();}
    if(e.target.closest('[data-calendar-wizard-close]')||e.target.id==='calendarWizardModal'){e.preventDefault();closeWizard();return;}
    if(e.target.closest('[data-calendar-save-draft]')){saveCalendarDraft();wizard.loadedDraft=true;wizard.savedAt=new Date().toISOString();renderWizard();return;}
    if(e.target.closest('[data-calendar-clear-draft]')){clearCalendarDraft({silent:true});wizard.draft.rules.calendarCustomization=store.defaultCalendarCustomization();wizard.preview=null;wizard.previewStale=false;wizard.loadedDraft=false;wizard.savedAt='';wizard.step=0;renderWizard();A.flash('#rulesMessage','Nuova configurazione avviata: i vincoli temporanei sono stati azzerati.','ok');return;}
    if(e.target.closest('[data-calendar-edit-rules]')){wizard.step=problemStep(wizard.preview);wizard.preview=null;wizard.previewStale=false;renderWizard();return;}
    if(e.target.closest('[data-calendar-cancel]')){closeWizard();return;}
    const remove=e.target.closest('[data-conflict-remove]');if(remove){applyConflictAction(remove.dataset.conflictRemove,'remove');return;}
    const step=e.target.closest('[data-calendar-step]');if(step&&wizard.draft&&!wizard.running){syncWizardFromDom();const target=Number(step.dataset.calendarStep);if(target===3){runPreview();return;}wizard.step=target;renderWizard();return;}
    if(e.target.closest('[data-calendar-prev]')){syncWizardFromDom();wizard.step=Math.max(0,wizard.step-1);renderWizard();return;}
    if(e.target.closest('[data-calendar-next]')){syncWizardFromDom();if(wizard.step===2){runPreview();return;}wizard.step=Math.min(3,wizard.step+1);renderWizard();return;}
    if(e.target.closest('[data-calendar-preview]')){runPreview();return;}
    if(e.target.closest('[data-calendar-confirm]')){confirmCalendar();return;}
    if(e.target.closest('[data-add-lock]')){syncWizardFromDom();wizard.draft.rules.calendarCustomization.firstRoundLocks.push({id:store.uid('lock'),groupName:wizard.draft.rules.format==='groups_knockout'?(wizard.draft.rules.groupConfigs[0]?.name||''):'',homeTeamId:'',awayTeamId:'',requiredDate:'',requiredTime:'',requiredField:'',mode:'hard'});renderWizard();return;}
    const rl=e.target.closest('[data-remove-lock]');if(rl){syncWizardFromDom();wizard.draft.rules.calendarCustomization.firstRoundLocks.splice(Number(rl.dataset.removeLock),1);renderWizard();return;}
    if(e.target.closest('[data-add-debut-time]')){syncWizardFromDom();markPreviewStale();const firstTime=store.calendarAvailableTimes(wizard.draft)[0]||'';wizard.draft.rules.calendarCustomization.teamDebuts.push({id:store.uid('debut'),teamId:'',kind:'exactTime',value:firstTime,mode:'hard'});renderWizard();return;}
    const rd=e.target.closest('[data-remove-debut]');if(rd){syncWizardFromDom();markPreviewStale();wizard.draft.rules.calendarCustomization.teamDebuts.splice(Number(rd.dataset.removeDebut),1);renderWizard();return;}
  });
  document.addEventListener('input',e=>{if(e.target.closest('#calendarWizardModal [data-debut-field],#calendarWizardModal [data-lock-field],#calendarWizardModal [data-cal-field]'))markPreviewStale();});
  document.addEventListener('change',e=>{if(e.target.closest('#calendarWizardModal [data-debut-field],#calendarWizardModal [data-lock-field],#calendarWizardModal [data-cal-field]'))markPreviewStale();if(e.target.closest('#calendarWizardModal [data-lock-field="groupName"],#calendarWizardModal [data-debut-field]')){syncWizardFromDom();renderWizard();}});
  document.addEventListener('dragstart',e=>{const row=e.target.closest('[data-criterion-index]');if(!row||isTouchDevice())return;e.dataTransfer.setData('text/plain',row.dataset.criterionIndex);row.classList.add('dragging');});
  document.addEventListener('dragend',e=>{e.target.closest('[data-criterion-index]')?.classList.remove('dragging');});
  document.addEventListener('dragover',e=>{const row=e.target.closest('[data-criterion-index]');if(!row||isTouchDevice())return;e.preventDefault();row.classList.add('drop-active');});
  document.addEventListener('dragleave',e=>{e.target.closest('[data-criterion-index]')?.classList.remove('drop-active');});
  document.addEventListener('drop',e=>{const row=e.target.closest('[data-criterion-index]');if(!row||isTouchDevice())return;e.preventDefault();row.classList.remove('drop-active');const from=Number(e.dataTransfer.getData('text/plain'));const to=Number(row.dataset.criterionIndex);moveCriterion(from,to);});
  UI.$('#rulesForm').addEventListener('submit',e=>{e.preventDefault();let check;A.commit(s=>{readInto(s);check=store.validateGeneration(s);if(!store.isCalendarFresh(s))s.calendarSignature='';});A.flash('#rulesMessage',check.ok?'Regole salvate. Nessun calendario e stato generato automaticamente: usa il wizard quando vuoi creare o sostituire le partite.':'Regole salvate, ma prima di generare correggi: '+check.message,check.ok?'ok':'error');fill();render();});
  UI.$('#generateCalendarBtn').addEventListener('click',()=>openWizard());
  window.NexoraAdminRefresh=function(){try{fill();render();}catch(_){}};window.addEventListener('ng:admin-state-loaded',()=>window.NexoraAdminRefresh());
})();
